const agentOutput = $input.first().json;
let text = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);

// Try to extract JSON from agent response
const jsonMatch = text.match(/```json\s*([\s\S]*?)\s*```/) || text.match(/```\s*([\s\S]*?)\s*```/);
if (jsonMatch) text = jsonMatch[1];

let ocrResult;
try {
  ocrResult = JSON.parse(text.trim());
} catch (e) {
  const objMatch = text.match(/\{[\s\S]*\}/);
  if (objMatch) {
    try { ocrResult = JSON.parse(objMatch[0]); }
    catch (e2) {
      // AI Agent failed to return valid JSON — use original extractedData
      ocrResult = $('Webhook').first().json.extractedData;
    }
  } else {
    ocrResult = $('Webhook').first().json.extractedData;
  }
}

// If AI Agent returned nulls, fallback to original
if (ocrResult && ocrResult.grand_total === null) {
  const original = $('Webhook').first().json.extractedData;
  if (original && original.grand_total !== null) {
    ocrResult = { ...original, expense_category: ocrResult.expense_category || 'other', confidence_score: ocrResult.confidence_score || 0.5 };
  }
}

const validations = [];
let isValid = true;

const subtotal = Number(ocrResult.subtotal) || 0;
const discount = Number(ocrResult.discount) || 0;
const vatAmount = Number(ocrResult.vat_amount) || 0;
const grandTotal = Number(ocrResult.grand_total) || 0;

const expectedTotal = subtotal - discount + vatAmount;
const totalDiff = Math.abs(expectedTotal - grandTotal);

if (totalDiff > 0.5) {
  validations.push({ field: 'grand_total', status: 'MISMATCH', message: `subtotal(${subtotal}) - discount(${discount}) + vat(${vatAmount}) = ${expectedTotal}, but grand_total = ${grandTotal}`, difference: totalDiff });
  isValid = false;
} else {
  validations.push({ field: 'grand_total', status: 'OK', message: 'Total calculation matches' });
}

const vatRate = Number(ocrResult.vat_rate) || 0;
if (vatRate > 0 && subtotal > 0) {
  const expectedVat = (subtotal - discount) * (vatRate / 100);
  const vatDiff = Math.abs(expectedVat - vatAmount);
  if (vatDiff > 0.5) {
    validations.push({ field: 'vat_amount', status: 'MISMATCH', message: `Expected VAT ${vatRate}% of ${subtotal - discount} = ${expectedVat.toFixed(2)}, but got ${vatAmount}`, difference: vatDiff });
    isValid = false;
  } else {
    validations.push({ field: 'vat_amount', status: 'OK', message: 'VAT calculation matches' });
  }
}

if (ocrResult.items && ocrResult.items.length > 0) {
  const itemsSum = ocrResult.items.reduce((sum, item) => sum + (Number(item.amount) || 0), 0);
  const itemsDiff = Math.abs(itemsSum - subtotal);
  if (itemsDiff > 0.5) {
    validations.push({ field: 'items_subtotal', status: 'MISMATCH', message: `Sum of items = ${itemsSum}, but subtotal = ${subtotal}`, difference: itemsDiff });
    isValid = false;
  } else {
    validations.push({ field: 'items_subtotal', status: 'OK', message: 'Items sum matches subtotal' });
  }
}

const requiredFields = ['document_number', 'date', 'vendor_name', 'grand_total'];
for (const field of requiredFields) {
  if (ocrResult[field] === null || ocrResult[field] === undefined || ocrResult[field] === '') {
    validations.push({ field, status: 'MISSING', message: `Required field '${field}' is missing` });
    isValid = false;
  }
}

if (ocrResult.date && !/^\d{4}-\d{2}-\d{2}$/.test(ocrResult.date)) {
  validations.push({ field: 'date', status: 'FORMAT_ERROR', message: `Date '${ocrResult.date}' is not in YYYY-MM-DD format` });
  isValid = false;
}

return [{
  json: {
    success: true,
    is_valid: isValid,
    data: ocrResult,
    validation: {
      status: isValid ? 'PASSED' : 'FAILED',
      checks: validations
    },
    processed_at: new Date().toISOString()
  }
}];
